// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const configGet = await fetch(`/platform/automation/v1/executions/${execution_id}/tasks/update-table-capacity/result`);
  const configBody = await configGet.json();

  if (!configBody.TableDescription || !configBody.TableDescription.ProvisionedThroughput) {
    console.log("DynamoDB capacity update failed!");
    throw new Error("DynamoDB capacity update failed!");
  }

  const throughput = configBody.TableDescription.ProvisionedThroughput;
  console.log("DynamoDB table scaled successfully");
  console.log("New RCU: " + throughput.ReadCapacityUnits);
  console.log("New WCU: " + throughput.WriteCapacityUnits);

  return configBody;
}
